class Solution:
    def minDeletionSize(self, strs):
        rows = len(strs)
        cols = len(strs[0])
        count = 0
        for c in range(cols):
            col = [strs[r][c] for r in range(rows)]
            if col != sorted(col):
                count += 1
        return count

