var minDeletionSize = function(strs) {
    let count = 0;
    const cols = strs[0].length;
    for (let c = 0; c < cols; c++) {
        for (let r = 0; r < strs.length - 1; r++) {
            if (strs[r][c] > strs[r + 1][c]) {
                count++;
                break;
            }
        }
    }
    return count;
};
